 2→-- Adds authorized_to relation table for per-identity permission overrides.
 3→-- Resolution order: per-identity override -> role-based scope -> agent_type scope -> blocked.
 4→
 5→DEFINE TABLE OVERWRITE authorized_to TYPE RELATION IN identity OUT authority_scope SCHEMAFULL;
 6→DEFINE FIELD OVERWRITE permission ON authorized_to TYPE string
 7→  ASSERT $value IN ["auto", "provisional", "propose", "blocked"];
