304→// ---------------------------------------------------------------------------
305→// SurrealDB Identity Lookups (adapter functions)
306→// ---------------------------------------------------------------------------
307→
308→import type { Surreal } from "surrealdb";
309→import type { ResolvedIdentity, ResolvedManager } from "./identity-lifecycle";
310→
311→type SurrealIdentityRow = {
312→  identityId: string;
313→  identityType: string;
314→  identityStatus?: string;
315→  managedBy?: string;
316→  revokedAt?: string;
317→};
318→
319→function createSurrealIdentityLookup(surreal: Surreal): LookupIdentity {
320→  return async (identityId: string) => {
321→    const rows = await surreal.query<[SurrealIdentityRow[]]>(
322→      `SELECT meta::id(id) AS identityId, type AS identityType, identity_status AS identityStatus, managed_by AS managedBy, revoked_at AS revokedAt FROM $identity;`,
323→      { identity: new RecordId("identity", identityId) },
324→    );
325→
326→    const row = rows[0]?.[0];
327→    if (!row) return undefined;
328→
329→    return {
330→      identityId: row.identityId,
331→      identityType: row.identityType as ResolvedIdentity["identityType"],
332→      identityStatus: (row.identityStatus ?? "active") as ResolvedIdentity["identityStatus"],
333→      managedBy: row.managedBy,
334→      revokedAt: row.revokedAt ? new Date(row.revokedAt) : undefined,
335→    };
336→  };
337→}
338→
339→function createSurrealManagerLookup(surreal: Surreal): LookupManager {
340→  return async (managerId: string) => {
341→    // Manager ID stored as raw string reference; look up identity by searching
342→    const rows = await surreal.query<[Array<{ identityStatus?: string }>]>(
343→      `SELECT identity_status AS identityStatus FROM identity WHERE meta::id(id) = $managerId LIMIT 1;`,
344→      { managerId },
345→    );
346→
347→    const row = rows[0]?.[0];
348→    if (!row) return undefined;
349→
350→    return {
351→      identityId: managerId,
352→      identityStatus: (row.identityStatus ?? "active") as ResolvedManager["identityStatus"],
353→    };
354→  };
355→}
