156→export function resolveEntityProject(
157→  entityText: string,
158→  promptText: string,
159→  projects: ProjectScopeRow[],
160→): RecordId<"project", string> | undefined {
161→  if (projects.length === 0) {
162→    return undefined;
163→  }
164→
165→  if (projects.length === 1) {
166→    return projects[0].id;
167→  }
168→
169→  const haystack = `${promptText}\n${entityText}`;
170→  const matchingProjects = projects.filter((project) => {
171→    const escaped = project.name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
172→    return new RegExp(`\\b${escaped}\\b`, "i").test(haystack);
173→  });
174→
175→  if (matchingProjects.length !== 1) {
176→    return undefined;
177→  }
178→
179→  return matchingProjects[0].id;
180→}
