 16→
 17→/** Identity status discriminated union. */
 18→export type IdentityStatus = "active" | "revoked" | "suspended";
 19→
 20→/** Resolved identity data needed for lifecycle checks. */
 21→export type ResolvedIdentity = {
 22→  identityId: string;
 23→  identityType: "human" | "agent" | "system";
 24→  identityStatus: IdentityStatus;
 25→  managedBy?: string;
 26→  revokedAt?: Date;
 27→};
 28→
 29→/** Resolved managing human data (when identity is managed). */
 30→export type ResolvedManager = {
 31→  identityId: string;
 32→  identityStatus: IdentityStatus;
 33→};
 34→
 35→/** Identity check result -- discriminated union. */
 36→export type IdentityCheckResult =
 37→  | { allowed: true }
 38→  | { allowed: false; reason: string; code: IdentityErrorCode };
 39→
 40→export type IdentityErrorCode =
 41→  | "identity_revoked"
 42→  | "identity_suspended"
 43→  | "manager_inactive"
 44→  | "identity_not_found"
 45→  | "manager_not_found";
 46→
 47→// ---------------------------------------------------------------------------
 48→// Port: Identity Lookup (function signature, no IO)
 49→// ---------------------------------------------------------------------------
 50→
 51→export type LookupIdentity = (
 52→  identityId: string,
 53→) => Promise<ResolvedIdentity | undefined>;
 54→
 55→export type LookupManager = (
 56→  managerId: string,
 57→) => Promise<ResolvedManager | undefined>;
 58→
 59→// ---------------------------------------------------------------------------
 60→// Pure Validation Functions
 61→// ---------------------------------------------------------------------------
 62→
 63→/** Check if an identity's own status allows operations. */
 64→export function checkIdentityStatus(
 65→  identity: ResolvedIdentity,
 66→): IdentityCheckResult {
 67→  if (identity.identityStatus === "revoked") {
 68→    return {
 69→      allowed: false,
 70→      reason: "Identity has been revoked",
 71→      code: "identity_revoked",
 72→    };
 73→  }
 74→
 75→  if (identity.identityStatus === "suspended") {
 76→    return {
 77→      allowed: false,
 78→      reason: "Identity is suspended",
 79→      code: "identity_suspended",
 80→    };
 81→  }
 82→
 83→  return { allowed: true };
 84→}
 85→
 86→/** Check if a managed agent's managing human is active. */
 87→export function checkManagerStatus(
 88→  identity: ResolvedIdentity,
 89→  manager: ResolvedManager | undefined,
 90→): IdentityCheckResult {
 91→  // Only applies to managed agents
 92→  if (!identity.managedBy) {
 93→    return { allowed: true };
 94→  }
 95→
 96→  if (!manager) {
 97→    return {
 98→      allowed: false,
 99→      reason: "Managing human identity not found",
100→      code: "manager_not_found",
101→    };
102→  }
103→
104→  if (manager.identityStatus !== "active") {
105→    return {
106→      allowed: false,
107→      reason: "Managing human is inactive",
108→      code: "manager_inactive",
109→    };
110→  }
111→
112→  return { allowed: true };
113→}
